std::vector<uint8_t> create_test_buffer(uint32_t packet_id, const std::string& username,
                                        const std::vector<uint32_t>& scores,
                                        const std::string& metadata) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << packet_id << username;
    stream << hexi::prefixed(scores);
    stream << hexi::null_terminated(metadata);

    return buffer;
}

TEST(NetworkPacket, Deserialize) {
    auto buffer = create_test_buffer(12345, "testuser", {100, 200, 300, 400}, "test metadata");

    NetworkPacket packet = deserialize_packet(buffer);

    EXPECT_EQ(12345, packet.packet_id);
    EXPECT_EQ("testuser", packet.username);
    EXPECT_EQ(std::vector<uint32_t>({100, 200, 300, 400}), packet.scores);
    EXPECT_EQ("test metadata", packet.metadata);
}

TEST(NetworkPacket, ExtractPacketInfo) {
    auto buffer = create_test_buffer(54321, "alice", {50, 75, 90}, "some metadata");

    PacketInfo info = extract_packet_info(buffer);

    EXPECT_EQ(54321, info.packet_id);
    EXPECT_EQ("alice", info.username);
}

