#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    stream >> packet.packet_id;

    // Read username with length prefix
    packet.username = stream.prefixed();

    // Read score count and then the scores vector
    uint32_t score_count;
    stream >> score_count;
    packet.scores.resize(score_count);
    for (auto& score : packet.scores) {
        stream >> score;
    }

    // Read metadata as null-terminated string
    packet.metadata = stream.cstr();

    // Skip any remaining padding bytes
    stream.skip(stream.remaining());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for zero-copy view of packet_id
    auto packet_id_span = stream.span<const uint32_t>(1);
    info.packet_id = packet_id_span[0];

    // Use prefixed adaptor for zero-copy username
    info.username = stream.prefixed();

    // Skip scores vector - read count then skip the data
    uint32_t score_count;
    stream >> score_count;
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}
