#include <gtest/gtest.h>
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>
#include <vector>

// Include the implementation
#include "implementation.hpp"

// Helper function to create header buffer
std::vector<uint8_t> create_header_buffer(uint8_t version, uint8_t flags, uint16_t packet_id) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << version << flags << packet_id;
    return buffer;
}

// Helper function to create message buffer
std::vector<uint8_t> create_message_buffer(const std::string& message) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << hexi::null_terminated(message);
    return buffer;
}

TEST(PacketHeader, ReadWithSpan) {
    auto buffer = create_header_buffer(1, 0x42, 12345);

    PacketHeader header = read_packet_header(buffer);

    EXPECT_EQ(1, header.version);
    EXPECT_EQ(0x42, header.flags);
    EXPECT_EQ(12345, header.packet_id);
}

TEST(PacketHeader, ReadDifferentValues) {
    auto buffer = create_header_buffer(2, 0xFF, 65535);

    PacketHeader header = read_packet_header(buffer);

    EXPECT_EQ(2, header.version);
    EXPECT_EQ(0xFF, header.flags);
    EXPECT_EQ(65535, header.packet_id);
}

TEST(MessageRead, ReadWithView) {
    auto buffer = create_message_buffer("Hello World");

    std::string_view message = read_message_until_delimiter(buffer);

    EXPECT_EQ("Hello World", message);
}

TEST(MessageRead, ReadEmptyMessage) {
    auto buffer = create_message_buffer("");

    std::string_view message = read_message_until_delimiter(buffer);

    EXPECT_TRUE(message.empty());
}

