const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    if (buffer.empty()) {
        return nullptr;
    }

    // Use Hexi's buffer adaptor to get the current read position
    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    // For const access, we need to work with the underlying buffer data
    // The read pointer is at the beginning of the readable data
    return buffer.data() + (adaptor.get_read_offset() % buffer.capacity());
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    if (buffer.empty()) {
        return nullptr;
    }

    // Use Hexi's buffer adaptor to get the current write position
    hexi::buffer_adaptor adaptor(buffer);

    // The write pointer is where new data will be written
    return buffer.data() + (adaptor.get_write_offset() % buffer.capacity());
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    BufferInfo info{0, 0};

    if (buffer.empty()) {
        return info;
    }

    // Use Hexi's buffer adaptor to check buffer state
    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    // Readable size is the amount of data available to read
    info.readable_size = adaptor.size();

    // Free space is the remaining capacity in the buffer
    info.free_space = buffer.capacity() - info.readable_size;

    return info;
}
