#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    if (buffer.empty()) {
        return nullptr;
    }

    // Create a buffer adaptor to access Hexi's buffer management
    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    // Get the current read position from the adaptor
    // The data() method returns the base pointer, and we need to add the read offset
    return reinterpret_cast<const uint8_t*>(adaptor.data()) + adaptor.get_read_position();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    if (buffer.empty()) {
        return nullptr;
    }

    // Create a buffer adaptor to access Hexi's buffer management
    hexi::buffer_adaptor adaptor(buffer);

    // Get the current write position from the adaptor
    // The data() method returns the base pointer, and we need to add the write offset
    return reinterpret_cast<uint8_t*>(adaptor.data()) + adaptor.get_write_position();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    BufferInfo info{0, 0};

    if (buffer.empty()) {
        return info;
    }

    // Create a buffer adaptor to access Hexi's buffer management
    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    // Readable size is the data between read and write pointers
    info.readable_size = adaptor.size();

    // Free space is the remaining capacity after the write pointer
    info.free_space = buffer.capacity() - adaptor.get_write_position();

    return info;
}

