#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Preview the first byte (data_type) without advancing the read pointer
    if (stream.available() < 1) {
        return result; // Not enough data for data_type
    }

    result.data_type = stream.peek<uint8_t>();

    // Check if we have enough data for the header (data_type + item_count)
    if (stream.available() < 5) { // 1 byte for data_type + 4 bytes for item_count
        return result;
    }

    // Read the data_type (this will advance the pointer)
    stream.get<uint8_t>(); // We already have the value from peek, but need to advance

    // Read the item_count
    uint32_t item_count = stream.get<uint32_t>();

    // Check if we have enough data for all items
    size_t required_bytes = item_count * (result.data_type == 0 ? sizeof(uint32_t) : sizeof(float));
    if (stream.available() < required_bytes) {
        return result; // Not enough data for all items
    }

    // Read items based on data_type
    if (result.data_type == 0) {
        // Integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            result.int_items[i] = stream.get<uint32_t>();
        }
    } else if (result.data_type == 1) {
        // Floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
