#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    std::vector<uint8_t> result;

    // Calculate how much data is actually available to read
    size_t available_data = storage.write_offset - storage.read_offset;
    if (available_data <= 0) {
        return result; // Return empty vector if no data available
    }

    // Limit the preview to available data
    size_t bytes_to_copy = (bytes_to_preview > available_data) ? available_data : bytes_to_preview;
    result.reserve(bytes_to_copy);

    // Copy data without advancing read pointer
    for (size_t i = 0; i < bytes_to_copy; ++i) {
        size_t index = storage.read_offset + i;
        // Handle potential wrap-around if needed (though intrusive_storage is linear within block)
        if (index < block_size) {
            result.push_back(static_cast<uint8_t>(storage.storage[index]));
        }
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Calculate readable size (data between read and write pointers)
    status.readable_size = storage.write_offset - storage.read_offset;

    // Calculate free space (remaining capacity in the buffer)
    status.free_space = block_size - storage.write_offset;

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use the clear() method that's available in intrusive_storage
    storage.clear();
}
