template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Get the available data size
    size_t available_size = buffer.size();

    // Limit preview to available data
    bytes_to_preview = std::min(bytes_to_preview, available_size);

    if (bytes_to_preview == 0) {
        return std::vector<uint8_t>();
    }

    // Create result vector
    std::vector<uint8_t> result;
    result.reserve(bytes_to_preview);

    // Handle circular buffer reading without advancing read pointer
    // We need to copy data in two parts if it wraps around the buffer end

    // Get current read position (this would typically be available via buffer methods)
    // Since we don't have direct access to read_ pointer, we need to use the buffer's interface

    // For a const static_buffer, we can use operator[] to access data without modifying read position
    // The buffer maintains read and write pointers internally

    // Copy data without advancing read pointer
    for (size_t i = 0; i < bytes_to_preview; ++i) {
        // Access data at current read position + offset without modifying read pointer
        // The buffer's operator[] should handle circular indexing
        std::byte data_byte = buffer[i];
        result.push_back(static_cast<uint8_t>(data_byte));
    }

    return result;
}
