```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

const void* get_read_pointer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Get the current read position and return pointer to that location
    // The buffer provides access to the underlying data through operator[]
    return &buffer[0];  // Returns pointer to the start of the buffer
}

struct BufferState {
    std::size_t size;
    const void* read_ptr;
    bool is_empty;
};

BufferState get_buffer_state(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferState state;
    state.size = buffer.size();        // Get current buffer size
    state.read_ptr = &buffer[0];       // Get read pointer (start of buffer)
    state.is_empty = buffer.empty();   // Check if buffer is empty

    return state;
}
```

However, looking more closely at the buffer adaptor implementation, I notice that it maintains separate read and write positions. Here's a more accurate implementation that accounts for the actual read position:

```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

const void* get_read_pointer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Get pointer to current read position in the buffer
    // Since buffer_adaptor maintains a read position, we need to access it properly
    if (buffer.empty()) {
        return nullptr;
    }
    return &buffer[0];  // For contiguous buffers, this points to the start
}

struct BufferState {
    std::size_t size;
    const void* read_ptr;
    bool is_empty;
};

BufferState get_buffer_state(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferState state;
    state.size = buffer.size();        // Get populated size
    state.is_empty = buffer.empty();   // Check if buffer is empty

    if (!state.is_empty) {
        state.read_ptr = &buffer[0];   // Pointer to start of buffer data
    } else {
        state.read_ptr = nullptr;      // No data available
    }

    return state;
}
```

The key points from the Hexi library fragments:
- `buffer_adaptor` has `size()` method to get the populated size
- `buffer_adaptor` has `empty()` method to check if buffer is empty  
- The adaptor works with contiguous ranges like `std::vector<std::byte>`
- The read pointer typically points to the start of the buffer for reading operations

