    // Write body content (this would be done by the caller after this function)
    // The body writing is not shown here as it's outside this function's scope

    // Now seek back to beginning to update the header with actual value
    buffer.write_seek(hexi::buffer_seek::begin, 0);
    buffer.write(&header_value, sizeof(header_value));

    // Seek back to end to continue writing (or to the position after body)
    // Since we don't know where the body ends, we'll seek to end
    buffer.write_seek(hexi::buffer_seek::end, 0);
