TEST(StringAdaptor, PrefixedVarintLong) {
    std::vector<char> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    std::string input(5000, 'A');
    write_string_prefixed_varint(stream, input);

    std::string output = read_string_prefixed_varint(stream);

    EXPECT_EQ(input, output);
}

TEST(StringAdaptor, PrefixedVarintEmpty) {
    std::vector<char> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    std::string input = "";
    write_string_prefixed_varint(stream, input);

    std::string output = read_string_prefixed_varint(stream);

    EXPECT_EQ(input, output);
    EXPECT_TRUE(output.empty());
}

