struct UnderrunInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t buff_size;
    bool occurred;
};

UnderrunInfo catch_buffer_underrun() {
    try {
        throw; // Re-throw the current exception
    } catch (const hexi::buffer_underrun& ex) {
        return UnderrunInfo{
            .read_size = ex.read_size,
            .total_read = ex.total_read,
            .buff_size = ex.buff_size,
            .occurred = true
        };
    } catch (...) {
        return UnderrunInfo{
            .read_size = 0,
            .total_read = 0,
            .buff_size = 0,
            .occurred = false
        };
    }
}

UnderrunInfo safe_read_with_underrun_check(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, void* destination, std::size_t length) {
    try {
        buffer.read(destination, length);
        return UnderrunInfo{
            .read_size = length,
            .total_read = 0, // We don't have access to total_read on success
            .buff_size = 0,  // We don't have access to buff_size on success
            .occurred = false
        };
    } catch (const hexi::buffer_underrun&) {
        return catch_buffer_underrun();
    }
}
