    std::size_t read_limit;
    bool occurred;
};

ReadLimitInfo catch_stream_read_limit() {
    ReadLimitInfo info = {0, 0, 0, false};

    try {
        throw; // Re-throw the current exception to catch it properly
    } catch (const hexi::pmc::stream_read_limit& e) {
        // Extract exception information
        info.read_size = e.read_size();
        info.total_read = e.total_read();
        info.read_limit = e.read_limit();
        info.occurred = true;
    } catch (...) {
        // Not a stream_read_limit exception, leave occurred as false
    }

    return info;
}

