        info.read_size = e.read_size();
        info.total_read = e.total_read();
        info.read_limit = e.read_limit();
        info.occurred = true;
    } catch (...) {
        // Other exceptions are not handled by this function
        throw; // Re-throw other exceptions
    }

    return info;
}
