Here's the complete implementation of the functions using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Serialize packet_id as regular uint32_t
    stream << packet.packet_id;

    // Serialize tags vector using prefixed_varint for compact encoding
    stream << hexi::prefixed_varint(packet.tags);

    // Serialize data string using prefixed_varint for compact encoding
    stream << hexi::prefixed_varint(packet.data);

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Deserialize packet_id
    stream >> packet.packet_id;

    // Deserialize tags vector using prefixed_varint
    stream >> hexi::prefixed_varint(packet.tags);

    // Deserialize data string using prefixed_varint
    stream >> hexi::prefixed_varint(packet.data);

    return packet;
}
```

