struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input buffer
    hexi::pmc::buffer_adaptor adaptor(buffer);

    Header header;

    // Use copy() to peek at header without advancing read cursor
    adaptor.copy(&header, sizeof(Header));

    // Use read_ptr() to verify pointer position hasn't changed
    const std::byte* ptr = adaptor.read_ptr();

    // Verify that the pointer still points to the beginning
    // (copy() should not advance the read cursor)
    if (ptr != reinterpret_cast<const std::byte*>(buffer.data())) {
        // Handle error - pointer advanced unexpectedly
        throw std::runtime_error("Read cursor advanced during peek");
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input buffer
    hexi::pmc::buffer_adaptor adaptor(buffer);

    std::vector<uint8_t> result;

    // Peek at first byte using copy()
    uint8_t first_byte;
    adaptor.copy(&first_byte, sizeof(first_byte));

    // Use read_ptr() to get current position
    const std::byte* peek_ptr = adaptor.read_ptr();

    // Condition: if first byte is non-zero, read more data
    if (first_byte != 0) {
        // Determine how much data to read based on the peeked value
        // Example: read number of bytes equal to the peeked value
        size_t bytes_to_read = std::min(static_cast<size_t>(first_byte), buffer.size());

        // Use read() to consume the data
        result.resize(bytes_to_read);
        adaptor.read(result.data(), bytes_to_read);

        // Verify that read_ptr() has advanced after reading
        const std::byte* new_ptr = adaptor.read_ptr();
        if (new_ptr == peek_ptr) {
            // Handle error - pointer didn't advance after read
            throw std::runtime_error("Read cursor didn't advance after read operation");
        }
    } else {
        // If condition not met, return empty vector
        // Read cursor remains unchanged since we only used copy()
        const std::byte* unchanged_ptr = adaptor.read_ptr();
        if (unchanged_ptr != peek_ptr) {
            throw std::runtime_error("Read cursor changed unexpectedly");
        }
    }

    return result;
}
